    @Test
    public void createDefaultFromEnum() {
        NavigationConfig config = NavigationConfig.createDefaultFromEnum();

        // Should have all Category enum values
        assertNotNull(config.getCategoryIds());
        assertFalse(config.getCategoryIds().isEmpty());

        // Check a known category
        assertTrue(config.isValidCategory("web"));
        assertTrue(config.isValidCategory("getting-started"));

        assertEquals(40, config.getTitleLimit());
        assertTrue(config.getFeatured().isEmpty());
        assertTrue(config.validate().isEmpty(), "Default config should be valid");
    }

    @Test
    public void getSubcategoriesForCategory() throws Exception {
        Path configFile = writeConfig("""
                categories:
                  - category: cloud
                    cat-title: Cloud
                    subcategories:
                      - subcategory: openshift
                        subcat-title: OpenShift
                      - subcategory: aws
                        subcat-title: AWS
                  - category: web
                    cat-title: Web
                """);

        NavigationConfig config = NavigationConfig.load(configFile);

        List<NavigationConfig.SubcategoryEntry> cloudSubcats = config.getSubcategories("cloud");
        assertEquals(2, cloudSubcats.size());
        assertEquals("openshift", cloudSubcats.get(0).getSubcategory());
        assertEquals("aws", cloudSubcats.get(1).getSubcategory());

        List<NavigationConfig.SubcategoryEntry> webSubcats = config.getSubcategories("web");
        assertTrue(webSubcats.isEmpty());

        List<NavigationConfig.SubcategoryEntry> unknownSubcats = config.getSubcategories("unknown");
        assertTrue(unknownSubcats.isEmpty());
    }

