    @Test
    public void loadLearningPaths() throws Exception {
        Path configFile = writeConfig("""
                categories:
                  - category: web
                    cat-title: Web

                learning-paths:
                  - path: rest-crud
                    path-title: Build a RESTful CRUD application
                    path-summary: Build a complete REST API with database access.
                    guides:
                      - rest.adoc
                      - hibernate-orm-panache.adoc
                """);

        NavigationConfig config = NavigationConfig.load(configFile);
        List<String> errors = config.validate();

        assertTrue(errors.isEmpty(), "Expected no errors but got: " + errors);
        assertEquals(1, config.getLearningPaths().size());

        NavigationConfig.LearningPathEntry lp = config.getLearningPaths().get(0);
        assertEquals("rest-crud", lp.getPath());
        assertEquals("Build a RESTful CRUD application", lp.getPathTitle());
        assertEquals("Build a complete REST API with database access.", lp.getPathSummary());
        assertEquals(List.of("rest.adoc", "hibernate-orm-panache.adoc"), lp.getGuides());
    }

